    s4 = lb.ref("s4", "( ⊥ ↔ ¬ ⊤ )", ref="df-fal", note="df-fal")
    res = lb.ref("res", "( ( ⊤ ⊽ ⊥ ) ↔ ⊥ )", s3, s4, ref="bitr4i", note="bitr4i")
    return lb.build(res)

