    s4 = lb.ref("s4", "( φ → ( ( ( ψ ∧ θ ) ∨ ( η ∧ ( ψ ⊻ θ ) ) ) ↔ ( ( χ ∧ τ ) ∨ ( ζ ∧ ( χ ⊻ τ ) ) ) ) )", s1, s3, ref="orbi12d", note="orbi12d")
    s5 = lb.ref("s5", "( cadd ψ θ η ↔ ( ( ψ ∧ θ ) ∨ ( η ∧ ( ψ ⊻ θ ) ) ) )", ref="df-cad", note="df-cad")
