def prove_cadcoma(sys: System) -> Proof:
    """Commutative law for the adder carry.  (Contributed by Mario Carneiro,
    4-Sep-2016.)
    """
    lb = ProofBuilder(sys, "cadcoma")
    s1 = lb.ref("s1", "( ( φ ∧ ψ ) ↔ ( ψ ∧ φ ) )", ref="ancom", note="ancom")
    s2 = lb.ref("s2", "( ( φ ⊻ ψ ) ↔ ( ψ ⊻ φ ) )", ref="xorcom", note="xorcom")
    s3 = lb.ref("s3", "( ( χ ∧ ( φ ⊻ ψ ) ) ↔ ( χ ∧ ( ψ ⊻ φ ) ) )", s2, ref="anbi2i", note="anbi2i")
    s4 = lb.ref("s4", "( ( ( φ ∧ ψ ) ∨ ( χ ∧ ( φ ⊻ ψ ) ) ) ↔ ( ( ψ ∧ φ ) ∨ ( χ ∧ ( ψ ⊻ φ ) ) ) )", s1, s3, ref="orbi12i", note="orbi12i")
    s5 = lb.ref("s5", "( cadd φ ψ χ ↔ ( ( φ ∧ ψ ) ∨ ( χ ∧ ( φ ⊻ ψ ) ) ) )", ref="df-cad", note="df-cad")
    s6 = lb.ref("s6", "( cadd ψ φ χ ↔ ( ( ψ ∧ φ ) ∨ ( χ ∧ ( ψ ⊻ φ ) ) ) )", ref="df-cad", note="df-cad")
    res = lb.ref("res", "( cadd φ ψ χ ↔ cadd ψ φ χ )", s4, s5, s6, ref="3bitr4i", note="3bitr4i")
    return lb.build(res)

def prove_cadcomb(sys: System) -> Proof:
    """Commutative law for the adder carry.  (Contributed by Mario Carneiro,
    4-Sep-2016.)  (Proof shortened by Wolf Lammen, 11-Jul-2020.)
    """
    lb = ProofBuilder(sys, "cadcomb")
    s1 = lb.ref("s1", "( cadd φ ψ χ ↔ ( ( φ ∨ ψ ) ∧ ( φ ∨ χ ) ∧ ( ψ ∨ χ ) ) )", ref="cadan", note="cadan")
    s2 = lb.ref("s2", "( ( ( φ ∨ ψ ) ∧ ( φ ∨ χ ) ∧ ( ψ ∨ χ ) ) ↔ ( ( φ ∨ χ ) ∧ ( φ ∨ ψ ) ∧ ( ψ ∨ χ ) ) )", ref="3ancoma", note="3ancoma")
    s3 = lb.ref("s3", "( ( ψ ∨ χ ) ↔ ( χ ∨ ψ ) )", ref="orcom", note="orcom")
    s4 = lb.ref("s4", "( ( ( φ ∨ χ ) ∧ ( φ ∨ ψ ) ∧ ( ψ ∨ χ ) ) ↔ ( ( φ ∨ χ ) ∧ ( φ ∨ ψ ) ∧ ( χ ∨ ψ ) ) )", s3, ref="3anbi3i", note="3anbi3i")
    s5 = lb.ref("s5", "( cadd φ ψ χ ↔ ( ( φ ∨ χ ) ∧ ( φ ∨ ψ ) ∧ ( χ ∨ ψ ) ) )", s1, s2, s4, ref="3bitri", note="3bitri")
    s6 = lb.ref("s6", "( cadd φ χ ψ ↔ ( ( φ ∨ χ ) ∧ ( φ ∨ ψ ) ∧ ( χ ∨ ψ ) ) )", ref="cadan", note="cadan")
    res = lb.ref("res", "( cadd φ ψ χ ↔ cadd φ χ ψ )", s5, s6, ref="bitr4i", note="bitr4i")
    return lb.build(res)

def prove_cadrot(sys: System) -> Proof:
    """Rotation law for the adder carry.  (Contributed by Mario Carneiro,
    4-Sep-2016.)
    """
    lb = ProofBuilder(sys, "cadrot")
    s1 = lb.ref("s1", "( cadd φ ψ χ ↔ cadd ψ φ χ )", ref="cadcoma", note="cadcoma")
    s2 = lb.ref("s2", "( cadd ψ φ χ ↔ cadd ψ χ φ )", ref="cadcomb", note="cadcomb")
    res = lb.ref("res", "( cadd φ ψ χ ↔ cadd ψ χ φ )", s1, s2, ref="bitri", note="bitri")
    return lb.build(res)

def prove_cadnot(sys: System) -> Proof:
    """The adder carry distributes over negation.  (Contributed by Mario
    Carneiro, 4-Sep-2016.)  (Proof shortened by Wolf Lammen, 11-Jul-2020.)
    """
    lb = ProofBuilder(sys, "cadnot")
    s1 = lb.ref("s1", "( ¬ ( φ ∧ ψ ) ↔ ( ¬ φ ∨ ¬ ψ ) )", ref="ianor", note="ianor")
    s2 = lb.ref("s2", "( ¬ ( φ ∧ χ ) ↔ ( ¬ φ ∨ ¬ χ ) )", ref="ianor", note="ianor")
    s3 = lb.ref("s3", "( ¬ ( ψ ∧ χ ) ↔ ( ¬ ψ ∨ ¬ χ ) )", ref="ianor", note="ianor")
    s4 = lb.ref("s4", "( ( ¬ ( φ ∧ ψ ) ∧ ¬ ( φ ∧ χ ) ∧ ¬ ( ψ ∧ χ ) ) ↔ ( ( ¬ φ ∨ ¬ ψ ) ∧ ( ¬ φ ∨ ¬ χ ) ∧ ( ¬ ψ ∨ ¬ χ ) ) )", s1, s2, s3, ref="3anbi123i", note="3anbi123i")
    s5 = lb.ref("s5", "( ¬ ( ( φ ∧ ψ ) ∨ ( φ ∧ χ ) ∨ ( ψ ∧ χ ) ) ↔ ( ¬ ( φ ∧ ψ ) ∧ ¬ ( φ ∧ χ ) ∧ ¬ ( ψ ∧ χ ) ) )", ref="3ioran", note="3ioran")
    s6 = lb.ref("s6", "( cadd φ ψ χ ↔ ( ( φ ∧ ψ ) ∨ ( φ ∧ χ ) ∨ ( ψ ∧ χ ) ) )", ref="cador", note="cador")
    s7 = lb.ref("s7", "( ¬ cadd φ ψ χ ↔ ( ¬ ( φ ∧ ψ ) ∧ ¬ ( φ ∧ χ ) ∧ ¬ ( ψ ∧ χ ) ) )", s5, s6, ref="xchnxbir", note="xchnxbir")
    s8 = lb.ref("s8", "( cadd ¬ φ ¬ ψ ¬ χ ↔ ( ( ¬ φ ∨ ¬ ψ ) ∧ ( ¬ φ ∨ ¬ χ ) ∧ ( ¬ ψ ∨ ¬ χ ) ) )", ref="cadan", note="cadan")
    res = lb.ref("res", "( ¬ cadd φ ψ χ ↔ cadd ¬ φ ¬ ψ ¬ χ )", s4, s7, s8, ref="3bitr4i", note="3bitr4i")
    return lb.build(res)

def prove_cad11(sys: System) -> Proof:
    """If (at least) two inputs are true, then the adder carry is true.
    (Contributed by Mario Carneiro, 4-Sep-2016.)
    """
    lb = ProofBuilder(sys, "cad11")
    s1 = lb.ref("s1", "( ( φ ∧ ψ ) → ( ( φ ∧ ψ ) ∨ ( χ ∧ ( φ ⊻ ψ ) ) ) )", ref="orc", note="orc")
    s2 = lb.ref("s2", "( cadd φ ψ χ ↔ ( ( φ ∧ ψ ) ∨ ( χ ∧ ( φ ⊻ ψ ) ) ) )", ref="df-cad", note="df-cad")
    res = lb.ref("res", "( ( φ ∧ ψ ) → cadd φ ψ χ )", s1, s2, ref="sylibr", note="sylibr")
    return lb.build(res)

def prove_cad1(sys: System) -> Proof:
    """If one input is true, then the adder carry is true exactly when at least
    one of the other two inputs is true.  (Contributed by Mario Carneiro,
    8-Sep-2016.)  (Proof shortened by Wolf Lammen, 19-Jun-2020.)
    """
    lb = ProofBuilder(sys, "cad1")
    s1 = lb.ref("s1", "( cadd φ ψ χ ↔ ( ( φ ∨ ψ ) ∧ ( φ ∨ χ ) ∧ ( ψ ∨ χ ) ) )", ref="cadan", note="cadan")
    s2 = lb.ref("s2", "( ( ( φ ∨ ψ ) ∧ ( φ ∨ χ ) ∧ ( ψ ∨ χ ) ) ↔ ( ( φ ∨ ψ ) ∧ ( ( φ ∨ χ ) ∧ ( ψ ∨ χ ) ) ) )", ref="3anass", note="3anass")
    s3 = lb.ref("s3", "( cadd φ ψ χ ↔ ( ( φ ∨ ψ ) ∧ ( ( φ ∨ χ ) ∧ ( ψ ∨ χ ) ) ) )", s1, s2, ref="bitri", note="bitri")
    s4 = lb.ref("s4", "( χ → ( φ ∨ χ ) )", ref="olc", note="olc")
    s5 = lb.ref("s5", "( χ → ( ψ ∨ χ ) )", ref="olc", note="olc")
    s6 = lb.ref("s6", "( χ → ( ( φ ∨ χ ) ∧ ( ψ ∨ χ ) ) )", s4, s5, ref="jca", note="jca")
    s7 = lb.ref("s7", "( χ → ( ( φ ∨ ψ ) ↔ ( ( φ ∨ ψ ) ∧ ( ( φ ∨ χ ) ∧ ( ψ ∨ χ ) ) ) ) )", s6, ref="biantrud", note="biantrud")
    res = lb.ref("res", "( χ → ( cadd φ ψ χ ↔ ( φ ∨ ψ ) ) )", s3, s7, ref="bitr4id", note="bitr4id")
    return lb.build(res)

def prove_cad0(sys: System) -> Proof:
    """If one input is false, then the adder carry is true exactly when both of
    the other two inputs are true.  (Contributed by Mario Carneiro,
    8-Sep-2016.)  (Proof shortened by Wolf Lammen, 21-Sep-2024.)
    """
    lb = ProofBuilder(sys, "cad0")
    s1 = lb.ref("s1", "( cadd φ ψ χ ↔ ( ( φ ∧ ψ ) ∨ ( χ ∧ ( φ ⊻ ψ ) ) ) )", ref="df-cad", note="df-cad")
    s2 = lb.ref("s2", "( ¬ χ → ( ( φ ∧ ψ ) → ( φ ∧ ψ ) ) )", ref="idd", note="idd")
    s3 = lb.ref("s3", "( ¬ χ → ( χ → ( φ ∧ ψ ) ) )", ref="pm2.21", note="pm2.21")
    s4 = lb.ref("s4", "( ¬ χ → ( ( χ ∧ ( φ ⊻ ψ ) ) → ( φ ∧ ψ ) ) )", s3, ref="adantrd", note="adantrd")
    s5 = lb.ref("s5", "( ¬ χ → ( ( ( φ ∧ ψ ) ∨ ( χ ∧ ( φ ⊻ ψ ) ) ) → ( φ ∧ ψ ) ) )", s2, s4, ref="jaod", note="jaod")
    s6 = lb.ref("s6", "( ¬ χ → ( cadd φ ψ χ → ( φ ∧ ψ ) ) )", s1, s5, ref="biimtrid", note="biimtrid")
    s7 = lb.ref("s7", "( ( φ ∧ ψ ) → cadd φ ψ χ )", ref="cad11", note="cad11")
    res = lb.ref("res", "( ¬ χ → ( cadd φ ψ χ ↔ ( φ ∧ ψ ) ) )", s6, s7, ref="impbid1", note="impbid1")
    return lb.build(res)

def prove_cadifp(sys: System) -> Proof:
    """The value of the carry is, if the input carry is true, the disjunction,
    and if the input carry is false, the conjunction, of the other two inputs.
    (Contributed by BJ, 8-Oct-2019.)
    """
    lb = ProofBuilder(sys, "cadifp")
    s1 = lb.ref("s1", "( χ → ( cadd φ ψ χ ↔ ( φ ∨ ψ ) ) )", ref="cad1", note="cad1")
    s2 = lb.ref("s2", "( ¬ χ → ( cadd φ ψ χ ↔ ( φ ∧ ψ ) ) )", ref="cad0", note="cad0")
    res = lb.ref("res", "( cadd φ ψ χ ↔ if- χ ( φ ∨ ψ ) ( φ ∧ ψ ) )", s1, s2, ref="casesifp", note="casesifp")
    return lb.build(res)

def prove_cadtru(sys: System) -> Proof:
    """The adder carry is true as soon as its first two inputs are the truth
    constant.  (Contributed by Mario Carneiro, 4-Sep-2016.)
    """
    lb = ProofBuilder(sys, "cadtru")
    s1 = lb.ref("s1", "⊤", ref="tru", note="tru")
    s2 = lb.ref("s2", "⊤", ref="tru", note="tru")
    s3 = lb.ref("s3", "( ( ⊤ ∧ ⊤ ) → cadd ⊤ ⊤ φ )", ref="cad11", note="cad11")
    res = lb.ref("res", "cadd ⊤ ⊤ φ", s1, s2, s3, ref="mp2an", note="mp2an")
    return lb.build(res)


